// Extrair dados da mensagem do WAHA
const raw = $input.first().json;
const body = raw.body || raw;

console.log('[02] Payload event:', body.event);
console.log('[02] Payload session:', body.session);

// WAHA envia evento 'message' com payload dentro de 'payload'
const payload = body.payload || {};

// chatId vem como '5541996893300@c.us' (já é o número real!)
const chatId = payload.from || payload.chatId || '';
const telefone = chatId.replace('@c.us', '').replace('@g.us', '').replace('@s.whatsapp.net', '');

const texto = payload.body || payload.text || '';
const nome = payload._data?.notifyName || payload.pushName || payload.notifyName || 'Cliente';

// Filtros
const ehGrupo = chatId.includes('@g.us');
const ehFromMe = payload.fromMe === true;
const vazio = !texto || texto.trim() === '';
const naoEhEvento = body.event !== 'message';

console.log(`[02] Telefone=${telefone} | Texto="${texto}" | Nome=${nome} | Grupo=${ehGrupo} | FromMe=${ehFromMe}`);

return [{
  json: {
    telefone,
    chatId,
    texto: texto.trim().toLowerCase(),
    texto_original: texto.trim(),
    nome,
    ignorar: ehGrupo || ehFromMe || vazio || naoEhEvento
  }
}];

const msg = $('02 | Extrair Mensagem').first().json;
const raw = $input.first().json?.value;

let estado = {
  etapa: 'inicio',
  nome: msg.nome,
  interesse: '',
  orcamento: '',
  entrada: '',
  financiamento: '',
  modelo_interesse: '',
  contato_preferido: '',
  timestamp_inicio: new Date().toISOString()
};

if (raw) {
  try {
    const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
    estado = { ...estado, ...parsed };
  } catch(e) {
    console.log('[05] Erro parse:', e.message);
  }
}

console.log(`[05] Etapa atual: ${estado.etapa}`);
return [{ json: { ...msg, estado } }];

const { texto, texto_original, telefone, chatId, nome, estado } = $input.first().json;
const etapaAtual = estado.etapa;
let proxEtapa = etapaAtual;
let resposta = '';
let finalizado = false;
let novoEstado = { ...estado };

console.log(`[06] Etapa=${etapaAtual} | Texto="${texto}"`);

switch(etapaAtual) {

  case 'inicio':
    resposta = `Olá! 👋 Bem-vindo à *Sky Motors*!\n\nSou a *Camila*, assistente virtual da Sky. Estou aqui pra te ajudar a encontrar o carro ideal! 🚗\n\nPrimeiro, pode me dizer seu nome?`;
    proxEtapa = 'aguardando_nome';
    break;

  case 'aguardando_nome':
    novoEstado.nome = texto_original;
    resposta = `Prazer, *${texto_original}*! 😊\n\nO que você está procurando?\n\n1️⃣ Comprar um carro\n2️⃣ Avaliação do meu carro\n3️⃣ Financiamento\n4️⃣ Falar com atendente\n\nDigite o número da opção:`;
    proxEtapa = 'aguardando_interesse';
    break;

  case 'aguardando_interesse':
    const ops = { '1': 'Comprar carro', '2': 'Avaliação', '3': 'Financiamento', '4': 'Atendente' };
    if (ops[texto]) {
      novoEstado.interesse = ops[texto];
      if (texto === '4') {
        resposta = `Certo! Um atendente vai entrar em contato. ⏰\n\nQual o melhor horário pra te ligar?\n\n1️⃣ Manhã (8h–12h)\n2️⃣ Tarde (12h–18h)\n3️⃣ Noite (18h–20h)`;
        proxEtapa = 'aguardando_horario';
      } else if (texto === '2') {
        resposta = `Ótimo! Pra avaliar seu veículo:\n\n📋 *Qual o modelo e ano do seu carro?*`;
        proxEtapa = 'aguardando_modelo_avaliacao';
      } else {
        resposta = `Ótimo! Vamos achar seu carro ideal. 🚘\n\nVocê tem algum modelo em mente?\n\nEx: *Civic 2020*, *HB20*, *Creta*, *Qualquer um*`;
        proxEtapa = 'aguardando_modelo';
      }
    } else {
      resposta = `Por favor, digite só o número:\n\n1️⃣ Comprar\n2️⃣ Avaliar meu carro\n3️⃣ Financiamento\n4️⃣ Atendente`;
    }
    break;

  case 'aguardando_modelo':
    novoEstado.modelo_interesse = texto_original;
    resposta = `Anotado: *${texto_original}* 👍\n\nQual a faixa de orçamento?\n\n1️⃣ Até R$ 30.000\n2️⃣ R$ 30.000 – R$ 50.000\n3️⃣ R$ 50.000 – R$ 80.000\n4️⃣ Acima de R$ 80.000\n5️⃣ Ainda pesquisando`;
    proxEtapa = 'aguardando_orcamento';
    break;

  case 'aguardando_modelo_avaliacao':
    novoEstado.modelo_interesse = texto_original;
    resposta = `Perfeito: *${texto_original}* 🚗\n\nO carro está *quitado* ou ainda *financiado*?\n\n1️⃣ Quitado\n2️⃣ Financiado`;
    proxEtapa = 'aguardando_status_veiculo';
    break;

  case 'aguardando_status_veiculo':
    novoEstado.financiamento = ({ '1': 'Quitado', '2': 'Financiado' })[texto] || texto_original;
    resposta = `Entendido! Vamos fazer a avaliação. 📞\n\nQual o melhor horário pra te ligar?\n\n1️⃣ Manhã (8h–12h)\n2️⃣ Tarde (12h–18h)\n3️⃣ Noite (18h–20h)`;
    proxEtapa = 'aguardando_horario';
    break;

  case 'aguardando_orcamento':
    const fx = { '1': 'Até R$ 30k', '2': 'R$ 30k–50k', '3': 'R$ 50k–80k', '4': 'Acima de R$ 80k', '5': 'Pesquisando' };
    novoEstado.orcamento = fx[texto] || texto_original;
    resposta = `Ótimo! Vai precisar de *financiamento*?\n\n1️⃣ Financiamento total\n2️⃣ Entrada + financiamento\n3️⃣ À vista\n4️⃣ Não sei`;
    proxEtapa = 'aguardando_financiamento';
    break;

  case 'aguardando_financiamento':
    const fm = { '1': 'Financiamento total', '2': 'Entrada + Financ.', '3': 'À vista', '4': 'Não definido' };
    novoEstado.financiamento = fm[texto] || texto_original;
    if (texto === '2') {
      resposta = `Quanto você tem disponível de entrada?\n\nEx: *R$ 5.000*, *R$ 10.000*, *Não sei*`;
      proxEtapa = 'aguardando_entrada';
    } else {
      resposta = `Perfeito! Última pergunta: qual o melhor horário pra ligar?\n\n1️⃣ Manhã (8h–12h)\n2️⃣ Tarde (12h–18h)\n3️⃣ Noite (18h–20h)`;
      proxEtapa = 'aguardando_horario';
    }
    break;

  case 'aguardando_entrada':
    novoEstado.entrada = texto_original;
    resposta = `Anotado! 👍\n\nQual o melhor horário pra ligar?\n\n1️⃣ Manhã (8h–12h)\n2️⃣ Tarde (12h–18h)\n3️⃣ Noite (18h–20h)`;
    proxEtapa = 'aguardando_horario';
    break;

  case 'aguardando_horario':
    const h = { '1': 'Manhã (8h–12h)', '2': 'Tarde (12h–18h)', '3': 'Noite (18h–20h)' };
    novoEstado.contato_preferido = h[texto] || texto_original;
    novoEstado.timestamp_fim = new Date().toISOString();
    resposta = `Perfeito, *${novoEstado.nome}*! ✅\n\nRecebi tudo:\n📋 ${novoEstado.interesse}\n🚗 ${novoEstado.modelo_interesse || 'Em aberto'}\n💰 ${novoEstado.orcamento || 'N/A'}\n💳 ${novoEstado.financiamento || 'N/A'}\n⏰ ${novoEstado.contato_preferido}\n\nUm consultor entrará em contato no horário indicado. 🤝`;
    proxEtapa = 'finalizado';
    finalizado = true;
    break;

  case 'finalizado':
    if (texto === 'reiniciar' || texto === 'oi' || texto === 'olá') {
      novoEstado = { etapa: 'inicio', nome: nome, timestamp_inicio: new Date().toISOString() };
      proxEtapa = 'aguardando_nome';
      resposta = `Olá novamente! 😊 Vamos começar uma nova consulta.\n\nPode me dizer seu nome?`;
    } else {
      resposta = `Olá! Seu cadastro já está com nossos consultores. Em breve entrarão em contato!\n\nDigite *reiniciar* pra começar nova consulta.`;
    }
    break;

  default:
    resposta = `Olá! Bem-vindo à *Sky Motors*! 🚗\n\nComo posso te ajudar?\n\n1️⃣ Comprar\n2️⃣ Avaliar meu carro\n3️⃣ Financiamento\n4️⃣ Atendente`;
    proxEtapa = 'aguardando_interesse';
}

novoEstado.etapa = proxEtapa;

return [{
  json: {
    telefone,
    chatId,
    nome: novoEstado.nome || nome,
    resposta,
    novoEstado,
    finalizado,
    estadoJson: JSON.stringify(novoEstado)
  }
}];

const item = $('06 | Motor SDR').first().json;
const e = item.novoEstado;
const agora = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

const ficha = `🚗 *NOVO LEAD QUALIFICADO — SKY MOTORS*\n━━━━━━━━━━━━━━━━━━━\n👤 *Nome:* ${e.nome || item.nome}\n📱 *WhatsApp:* ${item.telefone}\n⏰ *Horário:* ${agora}\n━━━━━━━━━━━━━━━━━━━\n📋 *Interesse:* ${e.interesse || 'N/I'}\n🚘 *Modelo:* ${e.modelo_interesse || 'Em aberto'}\n💰 *Orçamento:* ${e.orcamento || 'N/I'}\n💳 *Pagamento:* ${e.financiamento || 'N/I'}\n💵 *Entrada:* ${e.entrada || 'N/A'}\n⏰ *Melhor horário:* ${e.contato_preferido || 'N/I'}\n━━━━━━━━━━━━━━━━━━━\n📲 *Abrir conversa:* https://wa.me/55${item.telefone}`;

return [{
  json: {
    telefone: item.telefone,
    chatId: item.chatId,
    nome: e.nome || item.nome,
    ficha,
    dataHora: agora,
    interesse: e.interesse,
    modelo_interesse: e.modelo_interesse,
    orcamento: e.orcamento,
    financiamento: e.financiamento,
    entrada: e.entrada,
    contato_preferido: e.contato_preferido
  }
}];
